using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    [ColumnName("Label")]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; }
}

public class TicketPredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class TrainingMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public int TrainSetSize { get; set; }
    public int TestSetSize { get; set; }
    public List<CategoryMetric> PerCategoryMetrics { get; set; } = [];
}

public class CategoryMetric
{
    public string Category { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly MLContext _mlContext;
    private readonly string _modelPath;
    private readonly string _dataPath;
    private readonly ILogger<TicketModelService> _logger;

    private TrainingMetrics? _lastMetrics;
    private string[]? _categoryNames;

    public TrainingMetrics? LastMetrics => _lastMetrics;
    public string[] CategoryNames => _categoryNames ?? [];

    public TicketModelService(ILogger<TicketModelService> logger, IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "ticket_model.zip");
        _logger = logger;
    }

    public void TrainAndSave()
    {
        _logger.LogInformation("Loading training data from {Path}", _dataPath);

        var data = _mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        _logger.LogInformation("Building training pipeline");

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label")
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model on test set");
        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        // Extract category names from the key-value mapping
        var labelColumn = predictions.Schema["Label"];
        var keyType = labelColumn.Type as Microsoft.ML.Data.KeyDataViewType;
        if (keyType != null)
        {
            var keyValues = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
            labelColumn.GetKeyValues(ref keyValues);
            _categoryNames = keyValues.DenseValues().Select(v => v.ToString()).ToArray();
        }
        _categoryNames ??= ["Billing", "General", "Technical"];

        var trainCount = (int)split.TrainSet.GetColumn<string>("Label").Count();
        var testCount = (int)split.TestSet.GetColumn<string>("Label").Count();

        _lastMetrics = new TrainingMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction,
            TrainSetSize = trainCount,
            TestSetSize = testCount,
            PerCategoryMetrics = metrics.PerClassLogLoss
                .Select((logLoss, i) => new CategoryMetric
                {
                    Category = i < _categoryNames.Length ? _categoryNames[i] : $"Class_{i}",
                    F1Score = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? 2 * metrics.ConfusionMatrix.PerClassPrecision[i] * metrics.ConfusionMatrix.PerClassRecall[i]
                          / (metrics.ConfusionMatrix.PerClassPrecision[i] + metrics.ConfusionMatrix.PerClassRecall[i] + 1e-10)
                        : 0,
                    Precision = i < metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? metrics.ConfusionMatrix.PerClassPrecision[i] : 0,
                    Recall = i < metrics.ConfusionMatrix.PerClassRecall.Count
                        ? metrics.ConfusionMatrix.PerClassRecall[i] : 0,
                })
                .ToList()
        };

        _logger.LogInformation(
            "Model evaluation — MacroAccuracy: {MacroAccuracy:F4}, MicroAccuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        _mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }

    public string GetModelPath() => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private readonly TicketModelService _modelService;

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
        TicketModelService modelService)
    {
        _predictionPool = predictionPool;
        _modelService = modelService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketPredictionResponse> Classify([FromBody] TicketRequest request)
    {
        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority,
        };

        var prediction = _predictionPool.Predict(input);

        var categories = _modelService.CategoryNames;
        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < categories.Length; i++)
        {
            confidence[categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketPredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence,
        });
    }

    [HttpGet("metrics")]
    public ActionResult<TrainingMetrics> GetMetrics()
    {
        var metrics = _modelService.LastMetrics;
        if (metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(metrics);
    }
}

